   240	    repo: &mut StoredRepository,
   241	) -> Result<RepoMutation<RepoRecord>, ApiError> {
   242	    ensure_pending_publish(repo)?;
   243	    let pending = repo
   244	        .pending_import
   245	        .take()
   246	        .ok_or_else(|| ApiError::bad_request("repo has no pending import to publish"))?;
   247	    let changes = pending_import_changes(&repo.policy, &pending);
   248	    let parent_ids = repo
   249	        .graph
   250	        .commits
   251	        .last()
   252	        .map(|commit| vec![commit.id.clone()])
   253	        .unwrap_or_default();
   254	    let logical_id = format!(
   255	        "rv_git_{}",
   256	        pending
   257	            .head_oid
   258	            .get(..12)
   259	            .unwrap_or(pending.head_oid.as_str())
   260	    );
   261	    repo.graph.commits.push(LogicalCommit {
   262	        id: logical_id,
   263	        parent_ids,
   264	        author_id: repo.record.owner_user_id.clone(),
   265	        author_visibility: AuthorVisibility::Visible,
   266	        message: format!("Import pushed {}", pending.default_branch),
   267	        changes,
   268	    });
   269	    repo.git_snapshot = Some(pending.git_snapshot);
   270	    repo.record.publication_state = RepoPublicationState::Published;
   271	    repo.first_push_token = None;
   272	    repo.bump_change_version();
