   304	fn preserve_existing_visibility_for_new_default(
   305	    repo: &mut StoredRepository,
   306	    default_visibility: Visibility,
   307	) -> Result<(), ApiError> {
   308	    let existing_visibility = existing_repo_paths(repo)?
   309	        .into_iter()
   310	        .map(|path| {
   311	            let visibility = repo.policy.effective_visibility(&path);
   312	            (path, visibility)
   313	        })
   314	        .collect::<Vec<_>>();
   315	    repo.policy.set_default_visibility(default_visibility);
   316	    for (path, visibility) in existing_visibility {
   317	        if repo.policy.effective_visibility(&path) == visibility {
   318	            continue;
   319	        }
   320	
   321	        let rule = match visibility {
   322	            Visibility::Public => VisibilityRule::public(path),
   323	            Visibility::Private => VisibilityRule::private(path),
   324	        };
   325	        repo.policy.add_rule(rule).map_err(ApiError::bad_request)?;
   326	    }
   327	    Ok(())
   328	}
